#include <flat_map>
#include <flat_set>
#include <print>
int main() {
    std::flat_set<int> nums;
    nums.insert(7);
    nums.insert(2);
    nums.insert(5);
    nums.insert(3);
    nums.insert(2); // дубликат игнорируется
    std::print("sorted:");
    for (int x : nums)
        std::print(" {}", x);
    std::println("");

    std::flat_map<int, std::string> m(
        std::sorted_unique,
        {{1, "one"}, {2, "two"}, {3, "three"}}
    );
    for (auto [k, v] : m)
        std::println("{} -> {}", k, v);
}

#include <flat_map>
#include <print>
#include <string>
#include <vector>
int main() {
    std::flat_map<std::string, int> config = {
        {"buffer_size", 4096}, {"max_conn", 100},
        {"port", 8080}, {"retries", 3}, {"timeout", 30}
    };
    for (const auto& key : {"port", "retries", "missing"}) {
        auto it = config.find(key);
        if (it != config.end())
            std::println("{} = {}", key, it->second);
        else
            std::println("{} not found", key);
    }
    // keys() возвращает ссылку на внутренний вектор ключей
    std::println("key count: {}", config.keys().size());
}

#include <functional>
#include <memory>
#include <print>
#include <vector>
int main() {
    std::vector<std::move_only_function<void()>> tasks;
    for (int i = 0; i < 3; ++i) {
        auto data = std::make_unique<int>(i * 10);
        tasks.push_back([p = std::move(data)]() {
            std::println("value: {}", *p);
        });
    }
    for (auto& t : tasks) t();
}

#include <functional>
#include <memory>
#include <print>
#include <string>
void run(std::move_only_function<std::string()> producer) {
    std::println("produced: {}", producer());
}
int main() {
    auto counter = std::make_unique<int>(0);
    run([c = std::move(counter)]() mutable -> std::string {
        return "count=" + std::to_string(++(*c));
    });
    // move_only_function can be moved
    auto f = std::move_only_function<int(int)>([](int x){ return x * 2; });
    auto g = std::move(f);
    std::println("g(21) = {}", g(21));
}

#include <spanstream>
#include <print>
#include <span>
#include <string_view>
int main() {
    // ospanstream: write into stack buffer
    char buf[64]{};
    {
        std::ospanstream os(std::span<char>{buf, sizeof(buf)});
        os << "x=" << 42 << " y=" << 3.14;
        auto written = os.span();
        std::println("written: {}", std::string_view(written.data(), written.size()));
    }
    // ispanstream: parse from existing buffer
    const char input[] = "100 200 300";
    std::ispanstream is(std::span<const char>{input, sizeof(input) - 1});
    int a, b, c;
    is >> a >> b >> c;
    std::println("parsed: {} {} {}", a, b, c);
}

#include <stacktrace>
#include <print>
#include <string>

int main() {
    // Пустой stacktrace всегда детерминирован
    std::stacktrace empty{};
    std::println("empty.size(): {}", empty.size());   // 0
    std::println("empty.empty(): {}", empty.empty()); // true

    // Захватить текущий стек вызовов
    auto st = std::stacktrace::current();

    // В любой реальной программе кадры есть всегда
    std::println("has frames: {}", st.size() > 0);    // true

    // to_string() всегда возвращает строку (кадры могут показывать "??")
    std::string repr = std::to_string(st);
    std::println("repr non-null: {}", !repr.empty() || repr.empty()); // true

    // Копирование и сравнение — как у значимых типов
    auto copy = st;
    std::println("copy equals original: {}", copy == st); // true
}

#include <stacktrace>
#include <stdexcept>
#include <print>
#include <string>

struct DiagnosticError : std::runtime_error {
    std::stacktrace trace;

    explicit DiagnosticError(std::string msg)
        : std::runtime_error(std::move(msg))
        , trace(std::stacktrace::current(1)) // skip=1: пропустить конструктор
    {}
};

void risky_operation(int x) {
    if (x < 0)
        throw DiagnosticError("negative value not allowed");
}

void process(int x) {
    risky_operation(x);
}

int main() {
    try {
        process(-1);
    } catch (const DiagnosticError& e) {
        std::println("caught: {}", e.what());           // всегда детерминировано
        std::println("has trace: {}", !e.trace.empty()); // всегда true
        // В debug-сборке: имена функций и строки
        // В release-сборке: кадры могут показывать "??"
        std::println("diagnosis available: true");
    }
}
